function sliderServices() {
    var swiper = new Swiper('.services .mySwiper', {
        slidesPerView: 2,
        spaceBetween: 30,
        speed: 500,
        navigation: {
            nextEl: ".services .swiper-button-next",
            prevEl: ".services .swiper-button-prev",
        },
        breakpoints: {
            320: {
                slidesPerView: 1,
                spaceBetween: 16,
            },
            577: {
                slidesPerView: 1.5,
                spaceBetween: 16,
            },
            769: {
                slidesPerView: 2,
                spaceBetween: 16,
            },
            993: {
                slidesPerView: 2,
                spaceBetween: 30,
            }
        }
    })
}

