function sliderRisks() {
    var swiper = new Swiper(".risks__sliders .mySwiper", {
        slidesPerView: 1,
        spaceBetween: 30,
        allowTouchMove: false,
    });
    var swiper2 = new Swiper(".risks__sliders .mySwiper2", {
        slidesPerView: 1,
        spaceBetween: 30,
        effect: "fade",
        speed: 500,
        thumbs: {
            swiper: swiper,
        },
        navigation: {
            nextEl: ".swiper-button-next",
            prevEl: ".swiper-button-prev",
        },
    });
}


$(document).ready(function () {
    sliderServices();
    sliderPartners();
    sliderNews();
    sliderRisks();

    // Menu
    if (window.innerWidth > 992) {
        $('.has-dropdown').hover(function () {
        $(this).toggleClass('has-dropdown--active')
        })
    }

    if (window.innerWidth < 992) {
        $('.has-dropdown').click(function () {
        $(this).toggleClass('has-dropdown--active')
        })
    }

    $('.burger').click(function () {
        $(this).toggleClass('burger--active')
        $('.header__list').toggleClass('header__list--active')
    })

    // Accordion
    $(".item-show").click(function() {
        if ($(this).hasClass("item-show--active")) {
            $(this).removeClass("item-show--active");
            $(this).siblings(".item-hidden").slideUp();
        } else {
            $(".item-show").removeClass("item-show--active");
            $(".item-hidden").slideUp();
            $(this).addClass("item-show--active");
            $(this).siblings(".item-hidden").slideDown();
        }
    });

})

// Services-main
document.addEventListener('DOMContentLoaded', () => {
    const wrap = document.querySelector('.services-main__inner');
    const area = document.querySelector('.services-main__items2');
    const boxes = document.querySelectorAll('.services-main__item');
    const els = document.querySelectorAll('.services-main__item2');

    if (!area || !wrap) return;

    area.style.position = 'absolute';

    boxes.forEach((box, index) => {
        box.addEventListener('mouseenter', () => {
            area.style.opacity = '1';
            area.style.pointerEvents = 'auto';

            const wrapRect = wrap.getBoundingClientRect();
            const boxRect = box.getBoundingClientRect();
            area.style.top = `${boxRect.top - wrapRect.top}px`;

            els.forEach(el => el.classList.remove('active'));
            if (els[index]) els[index].classList.add('active');

            boxes.forEach(b => b.classList.remove('active'));
            box.classList.add('active');
        });
    });
});